-- Books catalog refactor: replaces Sheets-driven catalog with first-class books table.
-- Seeded from data/books-catalog-snapshot.json (generated by scripts/books-catalog-audit.ts).

-- 1. New tables
CREATE TABLE IF NOT EXISTS "books" (
  "id" text PRIMARY KEY NOT NULL,
  "canonical_key" text,
  "title" text NOT NULL,
  "author" text NOT NULL DEFAULT '',
  "tags" jsonb NOT NULL DEFAULT '[]'::jsonb,
  "type" text NOT NULL DEFAULT 'book',
  "size" text NOT NULL DEFAULT '',
  "pages" integer,
  "published_date" text NOT NULL DEFAULT '',
  "text_url" text NOT NULL DEFAULT '',
  "description" text NOT NULL DEFAULT '',
  "cover_url" text,
  "why_read" text,
  "recommendation_link" text,
  "reading_status" text,
  "visibility" text NOT NULL DEFAULT 'hidden',
  "is_new" boolean NOT NULL DEFAULT FALSE,
  "sort_order" integer NOT NULL DEFAULT 0,
  "source" text NOT NULL DEFAULT 'admin',
  "source_submission_id" text,
  "legacy_sheets_row_id" text,
  "created_at" timestamp NOT NULL DEFAULT now(),
  "updated_at" timestamp NOT NULL DEFAULT now(),
  "published_at" timestamp,
  "hidden_at" timestamp,
  "archived_at" timestamp,
  CONSTRAINT "books_visibility_check" CHECK ("visibility" IN ('hidden','published')),
  CONSTRAINT "books_type_check" CHECK ("type" IN ('book','article')),
  CONSTRAINT "books_source_check" CHECK ("source" IN ('admin','submission','sheets_import')),
  CONSTRAINT "books_reading_status_check" CHECK ("reading_status" IS NULL OR "reading_status" IN ('reading','read'))
);
CREATE INDEX IF NOT EXISTS "books_visibility_idx" ON "books"("visibility");
CREATE INDEX IF NOT EXISTS "books_source_submission_id_idx" ON "books"("source_submission_id");
CREATE UNIQUE INDEX IF NOT EXISTS "books_source_submission_id_unique" ON "books"("source_submission_id") WHERE "source_submission_id" IS NOT NULL;
CREATE INDEX IF NOT EXISTS "books_canonical_key_idx" ON "books"("canonical_key");
CREATE INDEX IF NOT EXISTS "books_sort_order_idx" ON "books"("sort_order");

CREATE TABLE IF NOT EXISTS "legacy_book_mappings" (
  "id" text PRIMARY KEY NOT NULL,
  "legacy_source" text NOT NULL,
  "legacy_id" text NOT NULL,
  "legacy_title" text,
  "legacy_author" text,
  "book_id" text REFERENCES "books"("id") ON DELETE SET NULL,
  "confidence" text NOT NULL,
  "resolution" text,
  "created_at" timestamp NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX IF NOT EXISTS "legacy_book_mappings_source_id_idx" ON "legacy_book_mappings"("legacy_source","legacy_id");
CREATE INDEX IF NOT EXISTS "legacy_book_mappings_book_id_idx" ON "legacy_book_mappings"("book_id");

-- 2. Seed books from prod snapshot (idempotent via ON CONFLICT)
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'cfeb4bf7-0f37-4ae5-8f4a-ebcbc4461d19', 'диктаторы обмана новое лицо тирании в xxi веке|сергей гуриев daniel treisman', 'Диктаторы обмана. Новое лицо тирании в XXI веке', 'Сергей Гуриев, Daniel Treisman', '["Путинизм"]'::jsonb, 'book', '', 500, '2022', 'https://babook.org/drupal/sites/default/files/2023-07/Dictators1.pdf',
  'Авторы объясняют, как в XXI веке изменились авторитарные режимы: если раньше диктаторы удерживали власть через страх, насилие и открытые репрессии, то сегодня всё чаще появляются так называемые «диктаторы обмана», которые действуют иначе — через манипуляцию информацией, пропаганду и имитацию демократических институтов. 

Авторы показывают, что современные автократы стараются выглядеть законными и популярными, допускают ограниченную оппозицию и выборы, но при этом контролируют медиа и формируют нужную картину реальности, что позволяет им удерживать власть без массового насилия и даже с поддержкой части общества. 

Такие режимы оказываются не слабее, а часто устойчивее старых диктатур, поскольку люди подчиняются им не из страха, а потому что верят в созданную ими версию реальности и не воспринимают систему как откровенно репрессивную.', 'https://24.place/wp-content/uploads/2025/04/guriev_treisman.png', 'Книга даёт понятный язык и модель, чтобы видеть, как именно работает манипуляция — через выборы, новости, образ «эффективного лидера» — и почему такие системы могут быть устойчивыми даже в мире с интернетом и формально демократическими институтами. То есть она полезна не столько как теория, сколько как инструмент: после неё легче считывать, где заканчивается демократия и начинается её имитация.', NULL, NULL, 'published', TRUE,
  0, 'submission', '128e529b-c0e8-488c-9f3d-86bf13f1d728', NULL, '2026-05-18T19:40:28.546Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'd4ea4fa8-5b45-4db7-8522-dc69087a92e0', 'почему одни страны богатые а другие бедные происхождение власти процветания и нищеты|daron acemoglu james a robinson', 'Почему одни страны богатые, а другие бедные: происхождение власти, процветания и нищеты', 'Daron Acemoglu, James A. Robinson', '["Государство"]'::jsonb, 'book', '', 510, '2012', 'https://webveblen.wordpress.com/wp-content/uploads/2018/06/acemoglu2.pdf',
  'Авторы предлагают объяснение мирового неравенства, которое выходит за рамки привычных факторов вроде географии или культуры, и показывают, что решающую роль играют политические и экономические институты — правила, определяющие, кто обладает властью и как распределяются ресурсы. Ключевая идея состоит в том, что богатые страны формируют инклюзивные институты, позволяющие широким слоям населения участвовать в экономике и получать выгоду от своей деятельности, тогда как бедные страны остаются в ловушке экстрактивных институтов, где узкая элита контролирует власть и ограничивает развитие. При этом менее очевидный тезис заключается в том, что такая ситуация часто поддерживается осознанно: правящие группы могут препятствовать реформам и экономическому росту, если эти изменения угрожают их позиции, то есть отсталость может быть не случайной, а логичным следствием структуры власти.', 'https://m.media-amazon.com/images/I/91j9vfc0GmL._AC_UF1000,1000_QL80_.jpg', 'Вместо привычных объяснений через «ошибки» или «отставание» книга показывает, что многие неэффективные системы остаются такими не случайно, а потому что это выгодно тем, кто у власти. Становится понятно, почему неудачные модели могут долго сохраняться без изменений.

В книге Россия рассматривается как пример страны с исторически сложившимися экстрактивными институтами, где власть и ресурсы сосредоточены в руках узкой элиты, что ограничивает участие общества и сдерживает устойчивое развитие: авторы показывают, что при такой системе рост может происходить, но он остаётся нестабильным, поскольку изменения, способные усилить конкуренцию и перераспределить власть, часто блокируются теми, кто заинтересован в сохранении существального порядка.', NULL, NULL, 'published', TRUE,
  1, 'submission', '37666c46-6a15-4211-87ce-ffd3f70cc199', NULL, '2026-05-18T19:35:51.179Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '85f77ce6-4ca5-4fe8-86bc-ef600f99ae56', 'contentious politics|charles tilly sidney tarrow', 'Contentious Politics', 'Charles Tilly, Sidney Tarrow', '["Государство"]'::jsonb, 'book', '', 288, '2015', 'https://books.apple.com/us/book/contentious-politics/id1024488233',
  'Авторы предлагают рассматривать протесты, социальные движения и революции как единый процесс, в котором группы предъявляют требования друг другу и государству, а политика развивается через взаимные действия и реакции.
Книга показывает, что за внешне разными событиями стоят сходные механизмы — мобилизация участников, ответ государства, эскалация или затухание конфликта. Эта динамика во многом определяет, во что в итоге выливается политическое противостояние.
Работа стала одной из ключевых в изучении политических конфликтов и задала современный подход, сместив фокус с отдельных причин на механизмы их развития — как такие процессы возникают, разворачиваются и к чему приводят.', 'https://m.media-amazon.com/images/I/81+S0YII1GL._AC_UF1000,1000_QL80_.jpg', 'Книга позволяет выйти за пределы описания событий и увидеть их общую логику: как формируются конфликты, почему они принимают ту или иную форму и к чему приводят. 
Она показывает, что решающими являются не столько причины недовольства, сколько динамика взаимодействия — кто мобилизуется и как на это отвечает государство.
В этом смысле она даёт рабочую аналитическую рамку — позволяет видеть за событиями устойчивые механизмы, а не случайный набор фактов.', NULL, NULL, 'published', TRUE,
  2, 'submission', '060209fd-3263-402d-b9d2-726256005e99', NULL, '2026-05-18T19:19:59.423Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '2cfd55c2-54bc-4f6d-87ca-d52aaf8a73d9', 'возвращение государства россия в нулевые 2000 2012|екатерина шульман', 'Возвращение государства. Россия в нулевые (2000-2012)', 'Екатерина Шульман', '["Путинизм"]'::jsonb, 'book', '', 208, '2023', 'https://flibusta.su/book/168011-vozvraschenie-gosudarstva-rossiya-v-nulevyie-2000-2012/',
  '«Возвращение государства» Екатерины Шульман — это исследование политической истории России в период 2000–2012 годов. Книга анализирует не столько события и фигуры, сколько изменение институтов: как перестраивались государственный аппарат, партийная система, суды, региональная политика, медиа и отношения между государством и обществом. Это попытка показать, как постепенно формируется и закрепляется политический режим и почему он начинает воспроизводить сам себя.

Аудио: 6 часов', 'https://www.moscowbooks.ru/image/book/784/orig/i784757.jpg?cu=20230707160505', 'Многие процессы, которые сегодня воспринимаются как данность, формировались именно в 2000 е годы — через постепенные изменения институтов, законов и управленческих практик. Шульман показывает, как именно происходит «возвращение государства»: через последовательное изменение правил игры — укрепление центра, перестройку политической системы и перераспределение власти. 

Книга помогает понять, почему система так устойчива, как она адаптируется и почему изменения происходят медленно и неравномерно. В этом смысле она полезна не только как разбор российской истории, но и как способ лучше понимать, как в целом формируются и закрепляются политические режимы.', NULL, NULL, 'published', TRUE,
  3, 'submission', '73fbdd23-6ddf-4f02-8df6-2ae6440789f2', NULL, '2026-05-18T19:01:48.853Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '50d64112-9332-4c05-830b-c764f66a8b45', 'оружие слабых повседневные формы крестьянского сопротивления|james scott', 'Оружие слабых. Повседневные формы крестьянского сопротивления', 'James Scott', '["Народные движения"]'::jsonb, 'book', '', 390, '1985', 'https://flibusta.su/book/376190-oruzie-slabyh-povsednevnye-formy-krestanskogo-soprotivlenia/',
  '«Оружие слабых» Джеймса Скотта — исследование повседневных форм сопротивления среди сельских жителей в Малайзии. Книга основана на полевой работе автора в конце 1970‑х годов в деревне Седака. 

В ходе экономических изменений конца 1960‑х – 1970‑х годов (включая механизацию и внедрение новых аграрных технологий) усилилось неравенство в деревне: более обеспеченные хозяйства выигрывали, а бедные теряли доступ к земле и доходам.

Вместо открытых протестов и восстаний Скотт показывает, как социально уязвимые группы используют скрытые и низко рискованные стратегии — саботаж, затягивание работы, притворное подчинение, мелкое присвоение ресурсов — чтобы противостоять неравенству и власти.

Эта книга расширила понятие сопротивления, и этот подход оказался применимым к рабочим, студентам, мигрантам и другим социальным группам — поэтому работа Скотта остаётся фундаментальной для политологии, социологии и антропологии.

Аудио: 17 часов', 'https://upload.wikimedia.org/wikipedia/en/e/ee/Weapons_of_the_Weak.jpg', 'Не все могут позволить себе открытую политическую борьбу: кто‑то занят выживанием, у кого‑то нестабильный миграционный статус, кто‑то (особенно женщины) не может рисковать из-за детей. В таких условиях становятся важны менее заметные, повседневные и скрытые формы сопротивления. 

Такие формы сопротивления легко недооценить, потому что они не приводят к быстрым и очевидным результатам. Но для многих людей это единственно возможный способ действовать: сохранять достоинство, пространство для автономии и оказывать давление на власть без критического риска.', NULL, NULL, 'published', TRUE,
  4, 'submission', '126eb6d4-2211-4b2b-86cb-fd27ae3eaffd', NULL, '2026-05-18T18:45:32.228Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '7a179b5a-a463-4dac-8bef-1fa1c4a3d005', 'работа капитализм экономика сопротивление|crimethinc', 'Работа: Капитализм. Экономика. Сопротивление.', 'CrimethInc', '["Капитализм"]'::jsonb, 'book', '', 340, '2021', 'https://www.rtpbooks.info/product/rabota-crimethinc/',
  'Почему во времена значительного технического прогресса нам приходится работать больше, чем когда-либо прежде? Почему, чем больше мы работаем, тем беднее становимся по сравнению с начальниками? Почему во времена кризисов люди так яро защищают свои рабочие места, если никто не любит работать?
Сможет ли капитализм пережить ещё одно столетие кризисов?
В книге «Работа» рассматриваются эти и многие другие вопросы.
Чтобы ответить на них, нам пришлось пересмотреть наш прежний взгляд на трудовую деятельность и выработать более тонкое понимание экономики. Мы провели месяцы, изучая непонятную историю и сравнивая опыт эксплуатации в повседневной жизни, постепенно создавая великую единую теорию современного
капитализма.', 'https://www.rtpbooks.info/wp-content/uploads/2017/09/job_7bc_fat60.jpg', 'Возможно, в ближайшее время многие из нас лишатся работы из-за ИИ или по другим причинам. Хочу взглянуть на тему работы с анти-капиталистических позиций.', NULL, NULL, 'published', TRUE,
  5, 'submission', 'eafb36e7-08b4-4159-a235-ed214edf5f41', NULL, '2026-04-26T11:50:40.933Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '500c4ef0-efed-4209-8bb3-d624a2ebf196', 'консенсус принятие решений в свободном обществе|peter gelderloos', 'Консенсус: Принятие решений в свободном обществе', 'Peter Gelderloos', '["Демократия"]'::jsonb, 'book', '', 106, '', 'https://we.riseup.net/assets/64520/consensus.pdf',
  'Это быстрое и лёгкое руководство по принятию коллективных решений описывает процесс прихода к консенсусу логично, шаг за шагом. Ясная форма позволяет этому пособию быть полезным не только в качестве инструкции для начинающих, но и как справочник для тех, кто уже знаком с принятием решений методом консенсуса. Будучи предназначенным в первую очередь для низовых политических и экологических групп, это руководство может быть полезно всякому, кто предпочитает сотрудничество, а не конфликт.', 'https://www.rtpbooks.info/wp-content/uploads/2017/06/cover_mask.png', 'Полезные инструменты и практики для совместного принятия решений', NULL, NULL, 'published', FALSE,
  6, 'submission', 'f1d2377b-c8d3-4bf1-a0e7-6a49af3b6d10', NULL, '2026-04-18T13:50:41.956Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '01173dc7-f3a5-4f19-8ddd-2e3d8d60a613', 'авторитарная россия|владимир гельман', 'Авторитарная Россия', 'Владимир Гельман', '["Путинизм"]'::jsonb, 'book', 'L', 337, '1/1/2021', 'http://kyiv-heritage.com/sites/default/files/%D0%93%D0%95%D0%9B%D0%AC%D0%9C%D0%90%D0%9D%20-%20%D0%90%D0%B2%D1%82%D0%BE%D1%80%D0%B8%D1%82%D0%B0%D1%80%D0%BD%D0%B0%D1%8F%20%D0%A0%D0%BE%D1%81%202021%20336%D1%81.pdf',
  'В августе 1991 года казалось, что демократия вот-вот наступит. Однако спустя десятилетия стало ясно: страна лишь отдалилась от свободы. Владимир Гельман объясняет, как это произошло. Без детерминизма и демонизации автор пишет о важных вехах политической истории страны: правлении Ельцина, формировании иерархии власти в 2000-х, возрождении оппозиции и застое 2010-х. Кроме того, Владимир Гельман дает определения ключевым терминам и концепциям и сравнивает российский опыт с другими странами.

А главное — автор дает развернутый ответ на вопрос «Что ждет Россию в будущем?» Станет ли автократический режим еще более жестким и репрессивным? Или нас ждет «ползучая демократизация»?', 'https://ir.ozone.ru/s3/multimedia-1-x/7240218405.jpg', NULL, NULL, NULL, 'published', FALSE,
  7, 'sheets_import', NULL, '39', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
