) VALUES (
  'f60fb15a-e83f-4e68-8e64-d8a8983f2f90', 'жизнь и времена либеральной|c b macpherson', 'Жизнь и времена либеральной', 'C. B. Macpherson', '["Демократия"]'::jsonb, 'book', '', 173, '1/1/1977', 'https://www.klex.ru/zu1',
  'Демократию ошибочно смешивать не только с выборами, но и с либерализмом. Макферсон даёт развёрнутый историко-теоретический анализ непростых отношений демократии и либерализма, которые привели к их несчастному браку во второй половине 20 века.', 'https://ndc.book24.ru/resize/410x590/pim/products/images/3b/8d/018edd38-aad5-705e-8b28-ea85dab53b8d.jpg', NULL, NULL, NULL, 'published', FALSE,
