INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '9aaa3760-d9b8-4b83-82c0-31d48a66a80f', 'принципы представительного правления|bernard manin', 'Принципы представительного правления', 'Bernard Manin', '["Демократия"]'::jsonb, 'book', '', 343, '1/1/1997', 'https://eupress.ru/books/index/item/id/8',
  'Манен критикует сложившуюся систему власти в современных демократиях, которая сложилась в результате принятия выборности власти как фундаментального принципа ее функционирования, что привело к формированию аристократической формы представительной системы. Принцип выборности заменил собой более эгалитарный – жребий, использовавшийся в классических республиках. Современная демократия как успешная политическая система, таким образом, стала возможна не столько благодаря этому принципу, сколько из-за действия других компонентов системы.

От А. Замятина:
«С этой книги следует начать всем, кто до сих пор считает, что сущностью демократии являются выборы и представительство».', 'https://eusp.org/sites/default/files/styles/weight_400/public/publications/preview/2020/Manin_cover.jpg?itok=AUAx--4t', NULL, 'Рекомендация Г. Юдина https://openuni.io/course/8-course-7-1/lesson/1/material/752/', NULL, 'published', FALSE,
  9, 'sheets_import', NULL, '37', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
