INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'edb09b95-62b3-493a-8e96-6a840af7560e', 'великая трансформация|karl polanyi', 'Великая трансформация', 'Karl Polanyi', '["Государство"]'::jsonb, 'book', 'M', 312, '1/1/1944', 'http://rustem-nureev.ru/wp-content/uploads/2011/01/277.pdf',
  'Исследование посвящено политическим и социальным процессам эпохи становления и развития капитализма. Поланьи утверждает, что рыночную экономику и национальное государство следует рассматривать не по отдельности, а как единое явление — общество рынка, или рыночное общество. Его возникновение разрушило традиционный социальный порядок — на протяжении большей части истории человечества экономическая деятельность не отделялась от социальных отношений, автор подчёркивал грандиозность перемен. Новый институциональный уклад породил контртенденции, которые привели к катаклизмам XX века', 'https://upload.wikimedia.org/wikipedia/ru/e/eb/The_Great_Transformation_1944.jpg', NULL, 'Отзыв Г. Юдина https://www.youtube.com/watch?v=D0pMpy1-Pjw', NULL, 'published', FALSE,
  12, 'sheets_import', NULL, '34', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '990b37c9-ed63-4aae-8f6e-99f09827a3f2', 'делать мнение новая политическая игра|patrick champagne', 'Делать мнение: новая политическая игра', 'Patrick Champagne', '["Демократия"]'::jsonb, 'book', 'L', 317, '1/1/1990', 'https://scepsis.net/library/id_1093.html',
  'Специалисты по опросам общественного мнения и телевидение — это не просто два новых игрока в политической игре. Они способствуют созданию системы «политика-медиа-опрос», в которой играют ведущую роль. Вездесущие специалисты по опросам общественного мнения официально претендуют на монополию на научное знание «народной воли» и неофициально предоставляют политическим партиям средства для манипулирования ею. Более того, освещение политики в СМИ, особенно уличных демонстраций, а также сопутствующие им опросы общественного мнения и барометры популярности, способствовали переосмыслению того, что мы сейчас понимаем под выражением «заниматься политикой».', 'https://m.media-amazon.com/images/I/61Ffy8ZppzL._AC_UF1000,1000_QL80_.jpg', 'Ученик Бурдье развил его статью о критике общественного мнения и написал книгу', NULL, NULL, 'published', FALSE,
  13, 'sheets_import', NULL, '33', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '4ea939d5-6980-47d1-8d01-6f45422c47d4', 'долгий двадцатый век|giovanni arrighi', 'Долгий двадцатый век', 'Giovanni Arrighi', '["Капитализм"]'::jsonb, 'book', 'XL', 727, '1/1/2006', 'https://crystalbook.ru/wp-content/uploads/2021/05/%D0%90%D1%80%D1%80%D0%B8%D0%B3%D0%B8-%D0%94%D0%B6.-%D0%94%D0%BE%D0%BB%D0%B3%D0%B8%D0%B9-%D0%B4%D0%B2%D0%B0%D0%B4%D1%86%D0%B0%D1%82%D1%8B%D0%B9-%D0%B2%D0%B5%D0%BA.pdf',
  'Описывает капитализм как череду сменяющих друг друга гегемоний от Генуи и Голландии до Британии и США, каждая из которых в свое время управляла мировой системой. Гегемония это не просто силовое доминирование. Это способность устанавливать правила, которые через идеологические инструменты представляются общими интересами, хотя на деле служат укреплению власти лидера. Сегодня, по его мнению, завершается американский цикл гегемонии, и мир движется в сторону азиатского лидерства, возможно, с доминирующей ролью Китая.', 'https://i.ebayimg.com/images/g/D4cAAOSw~y9ZKUGZ/s-l640.jpg', NULL, NULL, NULL, 'published', FALSE,
  14, 'sheets_import', NULL, '32', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '7b86809e-5556-49ec-811a-67657d0555cd', 'миросистемный анализ|immanuel wallerstein', 'Миросистемный анализ', 'Immanuel Wallerstein', '["Капитализм"]'::jsonb, 'book', 'M', 248, '1/1/2006', 'https://socioline.ru/files/5/48/vallerstain_i._-_analiz_mirovyh_sistem_i_situaciya_v_sovremennom_mire_-_2001.pdf',
  'Автор утверждает, что бедность стран третьего мира - это закономерность рыночной системы, а не ее отклонение. Объясняет, что такой порядок возможен из-за союза национальных государств и корпораций, где первые силой продвигают интересы вторых. Подчеркивает роль социальных наук в политике: они не только изучают реальность, но и формируются в историческом контексте, отражая интересы элит. Это понимание позволяет глубже осмыслить современные общественно-политические институты.', 'https://images-na.ssl-images-amazon.com/images/S/compressed.photo.goodreads.com/books/1391537270i/20731014.jpg', NULL, NULL, NULL, 'published', FALSE,
  15, 'sheets_import', NULL, '31', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '21c5149a-d79b-4ca2-8958-cdc8524c9589', 'капитал и идеология|thomas piketty', 'Капитал и идеология', 'Thomas Piketty', '["Капитализм"]'::jsonb, 'book', 'XL', 1150, '1/1/2019', 'https://fb2.top/kapital-i-ideologiya-749702',
  'Французский экономит Пикетти утверждает, что неравенство в большей степени является политическим и идеологическим феноменом, чем экономическим. Исторический прогресс, по его мнению, достигается через борьбу за равный доступ к благам, а не через оправдание иерархий и частной собственности. Он рассматривает примеры обществ, которые стремились к большему равенству, будь то социалистические проекты XX века или европейские социальные государства. Пикетти подчеркивает: справедливое общество - это не абсолютное равенство, а доступ каждого к как можно большему количеству общественных благ', 'https://pictures.abebooks.com/inventory/md/md31962839062.jpg', NULL, NULL, NULL, 'published', FALSE,
  16, 'sheets_import', NULL, '30', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'a5accc50-0d70-4ebe-8916-02199ff0a3ac', 'размышления о представительном правлении|john stuart mill', 'Размышления о представительном правлении', 'John Stuart Mill', '["Демократия"]'::jsonb, 'book', 'L', 340, '1/1/1861', 'https://readli.net/rassuzhdeniya-o-predstavitelnom-pravlenii/',
  'Одна из наиболее острых и прозорливых книг ведущего англоязычного мыслителя XIX века. В ней Милль обосновывает необходимость парламентской формы правления со всеобщим представительством от всех классов, что позволит избежать «тирании большинства», диктующей просвещенным меньшинствам свои средние, вернее, посредственные вкусы и представления', 'https://cdn.litres.ru/pub/c/cover_415/55024235.webp', NULL, 'Г. Юдин рекомендует https://openuni.io/course/8-course-7-1/lesson/1/material/752/', NULL, 'published', FALSE,
  17, 'sheets_import', NULL, '29', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '3e2e2e91-49ce-46ea-85be-2f136fb37366', 'arguing with zombies economics politics and the fight for a better future|paul krugman', 'Arguing with Zombies: Economics, Politics, and the Fight for a Better Future', 'Paul Krugman', '["Капитализм"]'::jsonb, 'book', '', 464, '1/1/2020', 'https://dokumen.pub/arguing-with-zombies-economics-politics-and-the-fight-for-a-better-future-hardcovernbsped-1324005017-9781324005018.html',
  'Врагами Кругмана являются «идеи зомби», высказанные в названии его книги, особенно вера в то, что бюджетный дефицит — это всегда плохо, и представление о том, что снижение налогов для богатых может принести пользу кому-либо, кроме плутократов, которые никогда не перестают за них просить', 'https://www.logobook.ru/make_nimage.php?uid=14672330', NULL, 'Обзор в Guardian https://www.theguardian.com/books/2020/may/03/arguing-with-zombies-review-paul-krugman-trump-republicans', NULL, 'published', FALSE,
  18, 'sheets_import', NULL, '28', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '6a328ad6-3fae-4736-829b-5f7ff5d649ac', 'социологическое воображение|charles mills', 'Социологическое воображение', 'Charles Mills', '["Демократия"]'::jsonb, 'book', '', 257, '1/1/1959', 'https://readli.net/sotsiologicheskoe-voobrazhenie/',
  'От Г. Юдина:
«Социологическое воображение должно быть не только у социологов, но и у любого человека. Оно помогает видеть своё положение в обществе не как индивидуальную проблему, а как часть более широкой социальной структуры. Например, если человек работает изо всех сил, но не может обеспечить себе достойную жизнь, социологическое воображение позволяет осознать, что таких "слабаков" миллионы, и это не его личный недостаток, а системная проблема общества»

Юдин также отмечает, что понимание того, что мир может быть устроен иначе, является важным элементом образования, особенно для молодых людей. Они должны воспринимать мир не как заранее предопределённый путь, а как пространство для проектирования, где они сами могут задавать вектор изменений', 'https://rgub.ru/searchcat/covers/BOOK-18096-large.jpg', NULL, NULL, NULL, 'published', FALSE,
  19, 'sheets_import', NULL, '27', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
