INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '6cd58304-1807-4e00-8f4e-e8d2648dfbea', 'войны в заливе не было|jean baudrillard', 'Войны в Заливе не было', 'Jean Baudrillard', '["Демократия"]'::jsonb, 'book', '', 82, '1/1/1991', 'https://books.google.rs/books?id=oc1FDQAAQBAJ&pg=PA5&source=gbs_selected_pages&cad=1#v=onepage&q&f=false',
  'Легендарный текст, прославивший Бодрийяра на весь мир. Война в Персидском заливе осталась в истории не только благодаря участию самой широкой международной коалиции, но и благодаря планетарной телетрансляции в режиме реального времени. Однако Бодрийяр утверждает, что это «не-война», это «не-событие», это то, чего не было. Сама постановка вопроса о, казалось бы, совершенно очевидном факте, о том, что видели все в прямом эфире, поначалу вызвала большой скандал, но теперь заголовок превратился в поговорку, мем, даже своего рода мантру. Эта работа Бодрийяра легла в основу не менее культового, чем «Матрица» голливудского фильма «Хвост виляет собакой».
', 'https://s.f.kz/prod/997/996856_550.jpg', 'Классика социологии', NULL, NULL, 'published', FALSE,
  21, 'sheets_import', NULL, '25', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'd4f6aff2-10d6-4a7d-8692-8de36c41260f', 'истоки современной политической мысли|quentin skinner', 'Истоки современной политической мысли', 'Quentin Skinner', '["Государство"]'::jsonb, 'book', '', 973, '1/1/1978', 'https://vse-svobodny.com/product/skinner-k-istoki-sovremennoy-politicheskoy-2-toma/',
  'В первом томе своего капитального исторического труда, проясняющего истоки политической мысли Нового времени, Квентин Скиннер излагает методологические принципы своего исследования и объясняет, чем они отличаются от традиционного «текстуалистского» подхода. В первой части тома речь идет об истории республиканского идеала свободы, который начал формироваться в XII — начале XIV века в городах Северной Италии благодаря местной правовой и риторической культуре, а также под влиянием схоластики. Вторая часть посвящена истории политической мысли XV века: Скиннера интересует вопрос о том, насколько она отличается от предшествующей традиции и, в частности, до какой степени Макиавелли наследует и трансформирует гуманистическое понятие добродетели.
Распространение гуманистической учености, происходившее в XV — начале XVI века за пределами Италии, составляет содержание третьей части тома. На примере сочинений Эразма Роттердамского, Томаса Мора, английских теоретиков «общего блага» Скиннер показывает, как изменяется традиционное гуманистическое отношение к добродетелям правителя, войне и социальному неравенству.

Второй том посвящен исследованию политической мысли Реформации и Контрреформации. Автор прослеживает основные этапы развития лютеранства и кальвинизма, показывая взаимосвязь их идей с томизмом и оккамизмом, а также с гуманистической мыслью и движением концилиаризма. В книге рассказывается история радикальных кальвинистских концепций сопротивления власти, в том числе принадлежавших французским и шотландским революционным теоретикам второй половины XVI в. Подробно рассматривается процесс зарождения теории абсолютной монархии. В заключении выдающийся английский историк и философ излагает концепцию возникновения современного понятия государства.', 'https://pictures.abebooks.com/isbn/9780521222846-uk.jpg', 'Ожидаю получить систематический обзор политических идей', NULL, NULL, 'published', FALSE,
  22, 'sheets_import', NULL, '24', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '532c5c26-de2a-4bd9-8149-958300baaf6e', 'the death of communal liberty a history of freedom in a swiss mountain canton|benjamin r barber', 'The Death of Communal Liberty: A History of Freedom in a Swiss Mountain Canton', 'Benjamin R. Barber', '["Демократия"]'::jsonb, 'book', '', 314, '1/1/1974', 'https://dokumen.pub/qdownload/the-death-of-communal-liberty-a-history-of-freedom-in-a-swiss-mountain-canton-9781400867172.html',
  'Сегодня Швейцария сталкивается с глубокой дилеммой-деревенская жизнь-это жизнь, пострадавшая от столкновения между общинным нормывалом и необходимостью национального выживания в промышленном, урбанизированном мире. Бенджамин Барбер прослеживает происхождение и эволюцию коммунальной свободы в группе альпийских деревень, которые составляют современный кантон Граубунден, и воссоздает свою острую тысячелетнюю борьбу за поддержание этой традиции перед лицом враждебной окружающей среды, иерархических феодальных институтов и европейской власти.', 'https://pup-assets.imgix.net/onix/images/9781400867172.jpg?w=410&auto=format', NULL, NULL, NULL, 'published', FALSE,
  23, 'sheets_import', NULL, '23', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '44613a46-8473-442a-8693-6ef1506dbf09', 'государство или цена порядка|вадим волков', 'Государство или Цена порядка', 'Вадим Волков', '["Государство"]'::jsonb, 'book', '', 160, '1/1/2018', 'https://eupress.ru/books/index/item/id/348',
  'Как с нами случилось государство? Какова его генеалогия, какие социальные группы его создавали и видоизменяли? Природа государства раскрывается здесь через процессы становления монополии легитимного насилия, налогообложения и юстиции. Что государство дает взамен, изымая и перераспределяя ресурсы общества?', 'https://imo10.labirint.ru/books/962503/cover.jpg/484-0', 'Надеюсь получить систематический обзор становления государства. Хочется понять, как люди жили до national state', NULL, NULL, 'published', FALSE,
  24, 'sheets_import', NULL, '22', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '34d93c8c-8e2e-4eb3-8d18-c5a10afa8e35', 'управляя пустотой размывание западной демократии|peter mair', 'Управляя пустотой. Размывание западной демократии', 'Peter Mair', '["Демократия"]'::jsonb, 'book', '', 216, '1/1/2019', 'https://readli.net/upravlyaya-pustotoy-razmyivanie-zapadnoy-demokratii/',
  'Во всех сложившихся демократиях Западной Европы происходит падение явки избирателей и сокращение числа членов ведущих партий. В книге ведущего ирландского политического ученого Питера Майра оценивается влияние этих изменений, которые свидетельствуют о том, что избиратели покидают политическую арену. Одновременно с этим политические элиты Европы превращаются в однородный профессиональный класс, тесно связанный с государственными институтами, которые предлагают относительную стабильность в мире таких непостоянных избирателей. ', 'https://content.img-gorod.ru/pim/products/images/4f/ad/018ee183-c7ca-77cd-96a9-986f87a74fad.jpg', NULL, NULL, NULL, 'published', FALSE,
  25, 'sheets_import', NULL, '21', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '60b160d4-6bdc-4876-8418-7df02f052581', 'краткая история равенства|thomas piketty', 'Краткая история равенства', 'Thomas Piketty', '["Капитализм"]'::jsonb, 'book', '', 394, '1/1/2021', 'https://books.yandex.ru/books/i1qwdSc2',
  'Ведущий мировой экономист и эксперт в вопросах неравенства представляет краткую и удивительно оптимистичную историю человеческого стремления к равенству, несмотря на кризисы и бедствия. Легко поддаться пессимизму, каждый день слыша о неравенстве. Однако в своей новой книге Тома Пикетти напоминает человечеству, что великий размах истории дает нам основания для оптимизма. Пикетти элегантно и лаконично анализирует великие идеи, которые определили современный мир и разукрасили его оттенками «плохо» и «хорошо»: рост капитализма, революции, империализм, рабство, войны и построение государства всеобщего благосостояния.

История равенства — это история насилия и социальной борьбы, перемежающаяся регрессами и катастрофами. Но, несмотря на все это, как показывает Пикетти, человеческие общества неуклонно двигались к более справедливому распределению доходов и активов, сокращению расового и гендерного неравенства и более широкому доступу к здравоохранению, образованию и гражданским правам. Эта книга — одновременно и прекрасное введение в новаторские идеи, развитые в монументальной книге Тома Пикетти «Капитал в XXI веке», и невероятно ценное самостоятельное исследование.', 'https://ndc.book24.ru/resize/410x590/pim/products/images/db/fb/018fa289-2f60-7589-97dc-af987acddbfb.jpg', NULL, NULL, NULL, 'published', FALSE,
  26, 'sheets_import', NULL, '20', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'cbdf455e-304b-4092-8a83-39987351b062', 'революция как момент истины|теодор шанин', 'Революция как момент истины', 'Теодор Шанин', '["Народные движения"]'::jsonb, 'book', '', 555, '1/1/1997', 'https://rabkrin.org/shanin-teodor-revolyutsiya-kak-moment-istinyi-kniga/',
  'Революция 1905-1907 гг. стала для России моментом истины. Развиваясь в направлении, неожиданном и для ее сторонников, и для ее противников, эта революция драматически обнажила новые связки социальных характеристик и способствовала поиску неортодоксальных решений, как политических, так и теоретических.

Введение от Шанина:
«Первая попытка России понять саму себя с точки зрения современной социальной теории приняла форму спора между славянофилами и западниками. Россия представлялась им или абсолютно уникальным явлением, или же отсталой частью Европы, находящейся ступенькой ниже других европейских стран на единой эволюционной лестнице. Россия не была ни тем, ни другим»', 'http://publ.lib.ru/ARCHIVES/SH/SHANIN_Teodor/.Online/Rkmi97O1.jpg', 'Помимо знакомства с событиями первой русской революции, я ожидаю, что книга расширит представление о политических альтернативах', 'Отзыв Г. Юдина https://www.youtube.com/watch?v=Elb91KmxuCw', NULL, 'published', FALSE,
  27, 'sheets_import', NULL, '19', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'a0338020-9985-46aa-88b6-67e57ceff28e', 'принуждение капитал и европейские государства|charles tilly', 'Принуждение, капитал и европейские государства', 'Charles Tilly', '["Государство"]'::jsonb, 'book', '', 360, '1/1/1992', 'http://kyiv-heritage-guide.com/sites/default/files/%D0%A2%D0%98%D0%9B%D0%9B%D0%98%20-%20%D0%9F%D1%80%D0%B8%D0%BD%D1%83%D0%B6%D0%B4%D0%B5%D0%BD%D0%B8%D0%B5%202009%20328c.pdf',
  'Цель данного исследования, по словам автора, при помощи подробного анализа истории Европы дать возможность понять истоки, характер и границы современной мировой системы. Принуждение и капитал являются основой для формирования государств. Начальная дата исследования определяется временем, когда после 990 г. европейские правители в отношении с подвластным населением все больше отходили от захвата необходимых для ведения войны средств в пользу их приобретения. Тем самым создавалась основа для соглашений между насилием и капиталом, обеспечивших участникам права и привилегии, а также форму современных государств.', 'https://urss.ru/covers500/94514.jpg', NULL, NULL, NULL, 'published', FALSE,
  28, 'sheets_import', NULL, '18', '2026-05-23T17:40:16.312Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '4d4f27d6-02dd-4d42-870e-9af31a204f44', 'общественное мнение не существует|pierre bourdieu', 'Общественное мнение не существует', 'Pierre Bourdieu', '["Демократия"]'::jsonb, 'article', 'M', NULL, '1/1/1972', 'http://bourdieu.name/content/obshhestvennoe-mnenie-ne-sushhestvuet',
  'Статья утверждает, что опросы — это инструмент конструирования, а не отражения реальности. Он ставит под сомнение три постулата: что мнение есть у всех, что все мнения равнозначны и что существует единый консенсус. На деле опросы навязывают вопросы и игнорируют силовые отношения', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c0/Pierre_Bourdieu_%281%29.jpg/500px-Pierre_Bourdieu_%281%29.jpg', 'Классика социологии', NULL, NULL, 'published', FALSE,
  29, 'sheets_import', NULL, '17', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '547eba39-eb6c-493f-8084-60c5fdb7350d', 'предпринимательское государство|marijana macukato', 'Предпринимательское государство', 'Marijana Macukato', '["Капитализм"]'::jsonb, 'book', 'L', 360, '1/1/2023', 'https://id.hse.ru/books/795933140.html',
  'Показывает, что миф об атлантах, единолично создавших инновационную экономику в своих гаражах, не соответствует той роли, которую на самом деле играло государство в части технологических разработок и рискованных вложений. Даёт новый взгляд на проблемы развития зелёной экономики и показывает, что в господствующей экономической парадигме человечество не сможет создать прорывные инновационные решения для спасения окружающей среды и климата', 'https://blog.metu.edu.tr/akcomak/files/2013/06/entrep.png', NULL, 'Отзыв А. Замятина https://t.me/zamyatinsk/194', NULL, 'published', FALSE,
  30, 'sheets_import', NULL, '16', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'd337c1b3-7f58-4cdd-8442-5c182ae2ac97', 'политика в эпоху жесткой экономии|wolfgang streeck armin sch fer', 'Политика в эпоху жесткой экономии', 'Wolfgang Streeck, Armin Schäfer', '["Капитализм"]'::jsonb, 'book', 'L', 392, '1/1/2015', 'https://rabkrin.org/politika-v-epohu-zhestkoy-ekonomii-2015-kniga/',
  'Многие зрелые демократии приближаются к ситуации фискального кризиса. На протяжении трех десятилетий странам ОЭСР приходится иметь дело с дефицитом бюджета и наращивать долг. В результате все меньшая доля доходов государства может идти на дискреционные расходы и социальные инвестиции, и независимо от того, какая партия находится у власти, ее руки оказываются связаны решениями, принятыми предыдущими правительства­ми. Текущий финансовый и бюджетный кризис усугубляется долгосрочным сокращением дискреционных расходов; проекты политических изменений больше не вызывают доверия. Многие граждане осознают это и отворачиваются от партийной политики, предпочитая не ходить на выборы', 'https://yandex-images.clstorage.net/F9Dv64E36/b0a31fKw/jwnpSIQQBkxfxoJdEwvMePbTSK9LG0LQAV6ZbBvOZoSyYgm6A2_AoNJpDjH7PQNJMdDgsbIks2YqL0H-xxFiFOvN3RgwtJPYqof3fHdKGe0iguwbrr5XgADbfD6szATH1UArmAEpp1RnTIvkj7z2nUI2EbblQNQyqu_zneEiYMOeKbgPciTVX5yUQUzQTgwaFpXYHZr4gLLVTMktve5GZnbiizrjOaTnR_6LB-5JdX7QpqX0x-DVALhcMf4SghDQXioL39GH1B1ct-LOEPxsyNTXGEw72ZLSxY87Li39BYSW0cnpAnqUNZXve8SeiGQcU-X0lJUQ9mIKLtH-c8JzIYwpmt5g93R_H2chXGNdbdhXpUsfCXhjgVedew_fHIaVpIG42xBpJjR3rtgHrxtkLEL3tNQnYTQzS_wB_mJz0TONytpdwtTFTx9G8y1QXl0oVYbIHysLwrP0vOo8b072VPfgeYuwGBUXJtyqpo1LdKwB9QaGldOEQ4ids1yCweJTfoo4PnPENG4_tlPOwJ0e6Td1u95pm-Gih18bbmwNN-aWc-jro8mWFKRM-ib_q5fvcKe1JGdwF0IKvjNsESFC83yoiEwxdlfOLKXQLhAOjcjWlMo96YsSAeTcuH1ODue3RJG7yqBYN6bUfgtHnzgkzSE1J8X2MsQBKy3xndCCcwE9SkqucrflLJ0H4F6Afl8Kh9bYPUspMMIVP2ov3i8Wl7ex6esRmeWlZ3_oxh5YdNwjZ7UUR6MGgfidkY-hMIMxDTuKjhCEpj-M1LHOEVxcGEZ1-Q9oiHIxNfzr3C68lHc2QfqKQYlXpMdNyTT-GkUcwaVUNKWjpzGaXtE-MqOzs-xoqQ5QFpT-T3aAjTE_Xrp2dXlP6RvQovb-m22-bRX0lfHbiHHZ5MaXjSvU_AmFLkC2hRT0cRRQyj8hHeNxUGGOiIjd4_QF_21Egc9QXbzapVVon5nqEFO2vFhPH_0WY', 'Хочется вписать дискуссию о бюджетном дефиците в более широкий контекст', NULL, NULL, 'published', FALSE,
  31, 'sheets_import', NULL, '15', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '73a106a4-2de2-45ed-8ee0-35700d2bbce0', 'недостойное правление|владимир гельман', 'Недостойное правление', 'Владимир Гельман', '["Путинизм"]'::jsonb, 'book', 'L', 225, '1/1/2019', 'http://kyiv-heritage.com/sites/default/files/%D0%93%D0%95%D0%9B%D0%AC%D0%9C%D0%90%D0%9D%20-%20%D0%9D%D0%B5%D0%B4%D0%BE%D1%81%D1%82%D0%BE%D0%B9%D0%BD%D0%BE%D0%B5%20%D0%BF%D1%80%D0%B0%D0%B2%D0%BB%D0%B5%D0%BD%D0%B8%D0%B5%202019%20254c.pdf',
  'Описание с сайта ВЦИОМа: «Недостойное правление» — это русский вариант английского bad governance, чьими характеристиками являются извлечение ренты и коррупция как принципы государственного управления, низкое качество госрегулирования и фундаментальное нарушение/извращение принципов верховенства права. Однако в России «недостойное правление» является не дефектом, считает Гельман, а средством удержания политической власти и экономического господства в руках правящих групп, то есть функциональным механизмом управления страной. Этот механизм не достался Российской Федерации в наследство от СССР и/или Российской империи, а сформировался как результат рациональной стратегии правящих групп, направленной на максимизацию власти и господства в политике, богатства и ренты в экономике и на сохранение такого положения дел на возможно более длительную перспективу. Гельман связывает создание такого политического режима в нашей стране со слабостью российского гражданского общества, которое почти не проявляло своего неприятия «недостойного правления» в форме коллективных действий, способных стать сильным вызовом для правящих групп. Именно пассивность граждан позволила чиновникам и олигархам выстроить режим, который не удалось создать в большинстве других стран сопоставимого с нами (а значит, довольно высокого) уровня развития', 'https://content.img-gorod.ru/pim/products/images/ae/45/018ee2c5-72c3-7df9-9efc-3aed9e97ae45.jpg', 'Один из ведущих современных социальных ученых России. Вероятно, это не исчерпывающая, но точно важная работа для понимания сложившейся в России системы управления', NULL, NULL, 'published', FALSE,
  32, 'sheets_import', NULL, '14', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'bf2962c3-bb46-4812-83a0-3caa3f0e6144', 'свобода до либерализма|quentin skinner', 'Свобода до либерализма', 'Quentin Skinner', '["Демократия"]'::jsonb, 'book', 'M', 113, '1/1/1998', 'https://www.eupress.ru/books/index/item/id/9',
  'В первой части автор стремится извлечь из небытия и реабилитировать неоримскую теорию свободных граждан и свободных государств, как она была развита в Англии эпохи раннего Нового времени. Анализ переходит в убедительную апологию природы, целей и задач интеллектуальной истории и истории идей

Как говорит профессор Скиннер: «Интеллектуальный историк способен помочь нам понять, в какой мере ценности, воплощенные в современном образе жизни и способе мыслить эти ценности, отражают серию выборов, сделанных между различными возможными мирами в различные исторические эпохи». Предлагаемый читателю очерк — одно из самых существенных современных высказываний о важности, актуальности и возможной радости от такого рода исторического исследования', 'https://ir.ozone.ru/s3/multimedia-z/6020179655.jpg', 'Я пришел к этой книге в ходе поиска на ответ, в чем разница республики и демократии. Ожидаю, что эта книга даст еще более широкую перспективу, но и ответа на мой вопрос будет не мало', NULL, NULL, 'published', FALSE,
  33, 'sheets_import', NULL, '13', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'c2885144-95ad-46e6-8610-55cd58a6448a', 'долг первые 5000 лет истории|david graeber', 'Долг: первые 5000 лет истории', 'David Graeber', '["Капитализм"]'::jsonb, 'book', '', 534, '1/1/2011', 'https://monoskop.org/images/c/cd/Greber_Devid_Dolg_pervyye_5000_let_istorii_2015.pdf',
  'Масштабное и революционное исследование истории товарно-денежных отношений с древнейших времен до наших дней, предпринятое американским антропологом, профессором Лондонской школы экономики и одним из «антилидеров» движения “Occupy Wall street”, придумавшим слоган «Нас - 99%». Гребер, опираясь на антропологические методы, выдвигает тезис, что в основе того, что мы традиционно называем экономикой, лежит долг, который на разных этапах развития общества может принимать формы денег, бартера, залогов, кредитов, акций и так далее. Один из императивов книги — вырвать экономику из рук «профессиональных экономистов», доказавших свою несостоятельность во время последнего мирового кризиса, и поместить ее в более широкий контекст истории культуры, политологии, социологии и иных гуманитарных дисциплин. Для широкого круга читателей.', 'https://picture.bookfrom.net/img/david-graeber/debt.jpg', 'Ожидаю, что книга позволит вписать в контекст сегодняшние дискуссии о слишком большом госдолге США и не только, необходимости бюджетной дисциплины и урезания лишних расходов. При этом я понимаю, что это не просто систематический обзор, а критическое высказывание и альтернативный взгляд', NULL, NULL, 'published', FALSE,
  34, 'sheets_import', NULL, '12', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'b1fc0c6f-e968-4cb7-8d72-9a6f6c74361e', 'долгое отступление|борис кагарлицкий', 'Долгое отступление', 'Борис Кагарлицкий', '["Левая идея"]'::jsonb, 'book', '', 332, '1/1/2023', 'https://yakniga.org/boris-kagarlitskiy/ebooks/dolgoe-otstuplenie',
  'Книга социолога-марксиста Бориса Кагарлицкого посвящена кризисному состоянию левых сил, серьезно утративших во всем мире свои позиции к началу XXI века. Парадоксальным образом этот кризис не только не связан с укреплением капиталистической системы, но, напротив, развивается на фоне нарастающих проблем, с которыми сталкивается господствующий порядок. Последовательно рассматривая основные дискуссии, разворачивавшиеся среди левых на протяжении современной истории (о социализме и демократии, плане и рынке, реформах и революции), а также развернувшиеся в последнее время споры (о развитии и экологии, классе и гендере, инфляции и безусловном базовом доходе), автор формулирует возможные подходы к политической стратегии, которые позволили бы преодолеть кризис движения.', 'https://imo10.labirint.ru/books/956013/cover.jpg/484-0', 'Хочу понять, что предлагают левые — как по конкретным проблемам, так и в целом по способам продвижения своей идеологии. Как реализовывать левую политику, если не все её принимают? Нет ли здесь внутреннего противоречия? Интересно, как выстраиваются позиции в дискуссиях внутри левого движения', NULL, 'read', 'published', FALSE,
  35, 'sheets_import', NULL, '11', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'b218ce91-07b4-4180-81db-db542c24f224', 'купленное время отсроченный кризис демократического капитализма|wolfgang streeck', 'Купленное время. Отсроченный кризис демократического капитализма', 'Wolfgang Streeck', '["Капитализм"]'::jsonb, 'book', 'M', 280, '1/1/2019', 'https://www.labirint.ru/books/683515/',
  'Автор анализирует истоки последних финансового, налогового и экономического кризисов, рассматривая их как часть длительной неолиберальной трансформации послевоенного капитализма, начавшейся в 1970-х годах', 'https://avatars.mds.yandex.net/get-mpic/16699368/2a0000019a46de0fd054a9dc5b07e61e64ad/450x600', 'Сегодня часто говорят о кризисе дефицита бюджета — нужно экономить. Критика высоких налогов и бюрократии исходит не только от ультраправых политиков, но и от классической либеральной и даже леволиберальной элиты. От книги ожидаю, что эти экономические процессы можно будет вписать в более широкую политическую перспективу', NULL, NULL, 'published', FALSE,
  36, 'sheets_import', NULL, '10', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '768a17d7-1d7e-4db2-8a46-2640cb12a801', 'будущая революция|murray bookchin', 'Будущая революция', 'Murray Bookchin', '["Левая идея"]'::jsonb, 'book', '', 248, '1/1/2023', 'https://www.rtpbooks.info/product/budushhaja-revoljucija-narodnye-assamblei-i-perspektiva-prjamoj-demokratii-mjurrej-bukchin/',
  'Девять коротких очерков, в которых автор рассуждает об актуальных проблемах современного революционного движения, критикует неудачи прошлых движений за социальные перемены и крупными мазками намечает контуры свободного общества будущего. Букчин показывает ошибочность прогнозов Маркса и считает классовый подход слишком узким для понимания современности и мобилизации широких масс. Большую мобилизующую силу он видит в проблемах разрушения окружающей среды, качества жилого пространства и участия в жизни общины.

Букчин последовательно выстраивает критику государства и парламентской демократии, предлагая взамен конфедералистскую альтернативу, основанную на сети принимающих решения народных ассамблей, которые делегируют отзываемых депутатов для решения проблем на разных уровнях. Коммуналистский проект Букчина задает принципы будущего общества: муниципальная экономика взамен капиталистической, социальная экология и самое широкое использование прямой демократии посредством народных собраний, объединенных в конфедерации.', 'https://ir.ozone.ru/s3/multimedia-z/6841291895.jpg', 'Собственно, попытка ответить на вопрос — А что, если не либеральная демократия?', NULL, NULL, 'published', FALSE,
  37, 'sheets_import', NULL, '9', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '9b351ca1-6513-43be-80d1-1547eb900984', 'доктирна шока|naomi klein', 'Доктирна шока', 'Naomi Klein', '["Капитализм"]'::jsonb, 'book', '', 656, '1/1/2009', 'https://royallib.com/read/klyayn_naomi/doktrina_shoka_stanovlenie_kapitalizma_katastrof.html#0',
  'История о том, как американская "свободная рыночная экномика" покоряет мир. Авторка считает, что экономисты Чикагской школы причастны к тому, что кризисные ситуации в разных странах мира оказались использованы для построения антидемократичских корпоратвных экономик. Наоми Кляйн называет это явление "доктриной шока". Она описывает, как полтики, экономисты и коммерсанты используют замешательство во вермя потрясений, чтобы проводить экономические реформы. Такие реформы известны как "шоковая терапия" - отсюда и название книги', 'https://files.books.ru/pic/4568001-4569000/4568937/004568937_1.jpg', 'Оказывается, «шоковая терапия» была не только в России. Хочется вписать эту практику в контекст, чтобы иметь возможность оценивать влияние', NULL, NULL, 'published', FALSE,
  38, 'sheets_import', NULL, '8', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'ed9b1d80-936b-4709-8e64-2c8f16fc9d1e', 'краткая история неолиберализма|david harvey', 'Краткая история неолиберализма', 'David Harvey', '["Капитализм"]'::jsonb, 'book', '', 288, '1/1/2007', 'https://royallib.com/read/harvi_devid/kratkaya_istoriya_neoliberalizma.html#0',
  'Основа для тех, кто не очень понимает, что такое неолиберализм, но хочет разобраться. Автор рассказывает, как направление зарождалось и распространялось по всему миру. Харви не только критикует опасные последствия неолибрельаного порядка, но и описывает альтернативы', 'https://avatars.mds.yandex.net/i?id=2a0000017a02fcd8f38ca3b8d15617962e87-4987760-images-thumbs&n=13', 'Ожидаю получить систематический обзор по неолиберализму', NULL, NULL, 'published', FALSE,
  39, 'sheets_import', NULL, '7', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '7e29bba2-c43e-4c8d-8fd4-5b370421df52', 'the semisovereign people|schattschneider', 'The semisovereign people', 'Schattschneider', '["Демократия"]'::jsonb, 'book', 'M', 180, '1/1/1960', 'https://archive.org/details/semisovereignpeo00scha/mode/2up',
  'Предполагается, что политики вынуждены балансировать между интересами общества и проводить компромиссную политику. Но это так не происходит. Если посмотреть на соц опросы о контроле над рождаемостью, бюджете, смертной казни, разводах, трудовых отношениях, налогах на сверхдоходы, свободе слова, рассовых отношения и так далее, то мы увидим, что общественное мнение по этим вопросам никак не влияет на политический курс, который реализуется в реальности. На самом деле группы с низкими доходами не представлены в этой конкуренции, в плюрализме мнений.', 'https://m.media-amazon.com/images/I/41AIzVBk9TL._UX300undefined_.jpg', 'При взгляде из России кажется, что на Западе всё получилось с демократией. А потом ты узнаешь, что и там много скепсиса. А потом узнаешь, что этот скепсис был предметом научных исследований еще в 1950-е. Кажется, это важнейший источник для понимания современной формы западной либеральной демократии

Эт работа суммирует разочарование 1950-х годов в способности американского политического режима обеспечивать самоуправление народа', 'Саммари от политолога https://adambrown.info/p/notes/schattschneider_the_semisovereign_people', NULL, 'published', FALSE,
  40, 'sheets_import', NULL, '6', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '3b6ea55c-3f4f-4b84-8b2a-3e11884a395e', 'демократия или демон и гегемон|артемий магун', 'Демократия, или Демон и Гегемон', 'Артемий Магун', '["Демократия"]'::jsonb, 'book', 'M', 152, '1/1/2016', 'https://eupress.ru/books/index/item/id/409',
  'Самая обширная русскоязычная работа по политической теории демократии, по которой вы можете начать ориентироваться в сюжетах внутри этого огромного понятия', 'https://imwerden.de/pdf/%D0%9C%D0%B0%D0%B3%D1%83%D0%BD_%D0%90%D1%80%D1%82%D0%B5%D0%BC%D0%B8%D0%B9_%D0%92%D0%BB%D0%B0%D0%B4%D0%B8%D0%BC%D0%B8%D1%80%D0%BE%D0%B2%D0%B8%D1%87.jpg', 'Ожидаю, что разрозненные представления о видах демократии можно будет свести к какой-то системе. Вряд ли это будет финальная система, но от нее можно будет отталкиваться, чтобы эффективнее усваивать новые понятия и строить свое понимание', NULL, NULL, 'published', FALSE,
  41, 'sheets_import', NULL, '5', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  '2193eb88-e975-4563-8aa7-ed0ef7be9e4b', 'патриот|алексей навальный', 'Патриот', 'Алексей Навальный', '["Путинизм"]'::jsonb, 'book', 'L', 398, '4/1/2024', 'https://www.onebookpublishing.org/products/patriot',
  'Мемуары российского политика и оппозиционного лидера Алексея Навального, которые он начал писать в 2020 году после отравления «Новичком» и продолжил работу над ними в заключении', 'https://www.dosye.com.ua/storage/images/222222222222/d7ff96de147b8f67bc55e3d9c0d1bac4.jpg', 'От книги я ожидаю понять и прочувствовать то, как Навальный видел Россию сегодня и завтра. Что его мотивировало и что ограничивало. Он символизирует большое демократическое движение. Его уроки могут быть полезны, если мы хотим участвовать в изменениях в России', NULL, NULL, 'published', FALSE,
  42, 'sheets_import', NULL, '4', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'f4ea5268-d72e-4f63-8721-dd5cdc64fcdc', 'заря всего|david wengrow david graeber', 'Заря всего', 'David Wengrow, David Graeber', '["Государство"]'::jsonb, 'book', 'L', 560, '1/1/2024', 'https://books.yandex.ru/books/VMifNlUI ',
  'Авторы бросают вызов доминирующим представлениям о развитии общества как о движении от эгалитарных групп охотников-собирателей — через аграрную революцию и урбанизацию — к созданию иерархических государств. По их мнению, этот традиционный нарратив  лишь воспроизводит мифы, укоренившиеся в исторической науке. Основываясь на данных археологии, антропологии и смежных дисциплин, полученных за последние десятилетия, Гребер и Уэнгроу предлагают посмотреть на социальную историю извне западного канона. «Заря всего» возникла как своего рода игра, неформальная дискуссия антрополога и археолога об истории человечества, и превратилась в захватывающее интеллектуальное путешествие', 'https://avatars.mds.yandex.net/get-mpic/4343038/2a00000195ffee2e0722be6d0aeecc0be6e3/orig', 'Книга обещает предложить альтернативный взгляд на наше прошлое, а значит — и на наше будущее. Как я понял, в начале авторы показывают, что объединяет такие разные подходы как гобсианство и руссоизм, в чем их общая проблема упрощения истории — и, отталкиваясь от этого, предлагают посмотреть на историю человечества как на бесчисленную череду социальных экспериментов. Которые в какой-то момент остановились. Почему?', 'Отзыв А. Замятина https://t.me/zamyatinsk/88', NULL, 'published', FALSE,
  43, 'sheets_import', NULL, '3', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "books" (
  "id","canonical_key","title","author","tags","type","size","pages","published_date","text_url",
  "description","cover_url","why_read","recommendation_link","reading_status","visibility","is_new",
  "sort_order","source","source_submission_id","legacy_sheets_row_id","published_at"
) VALUES (
  'cacd47f8-388d-4d5a-8232-787d9cd9f69f', 'революционный темперамент париж в 1748 1789 годах|robert darnton', 'Революционный темперамент. Париж в 1748–1789 годах', 'Robert Darnton', '["Народные движения"]'::jsonb, 'book', 'M', 242, '1/1/2026', 'https://books.yandex.ru/books/OPaDWzEK',
  'Как Париж пришел к 1789 году? Что на самом деле думали и чувствовали парижане в десятилетия, предшествовавшие Великой французской революции? Выдающийся историк Р. Дарнтон в своей новой книге предлагает оригинальный ответ: он исследует не столько политико-экономические причины революции, сколько созревание особого «революционного темперамента» — коллективного умонастроения, которое сделало возможным взрыв 1789 года. Дарнтон погружает читателя в гущу парижской жизни 1748–1789 годов, прослеживая формирование нового общественного сознания через уникальную «мультимедийную систему» Старого порядка: как новости о войне, налогах, королевских любовницах и полетах на воздушном шаре превращались в песни, памфлеты, слухи и сплетни, распространяясь от салонов и кофеен до рынков и мастерских. Анализируя циркуляцию этих информационных потоков, автор реконструирует социальный опыт горожан и объясняет, как еще за сорок лет до взятия Бастилии в их сознании закрепилась готовность к радикальным переменам.', 'https://api.bookmate.ru/assets/books-covers/f2/de/OPaDWzEK-ipad.jpeg?image_hash=4744330b9afb17ec51a5ca8a5ad39203', 'Французская Революция ассоциируется одновременно с большой эмпансипацией и с большим насилием. Сегодня, когда мы жаждем Революции, хочется разобраться, как они работают', 'Рекомендация А. Замятина https://t.me/zamyatinsk/535', NULL, 'published', TRUE,
  44, 'sheets_import', NULL, '2', '2026-05-23T17:40:16.313Z'::timestamp
) ON CONFLICT ("id") DO NOTHING;

