-- 4. book_submissions.book_id (FK to books)
ALTER TABLE "book_submissions" ADD COLUMN IF NOT EXISTS "book_id" text;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'book_submissions_book_id_fk') THEN
    ALTER TABLE "book_submissions" ADD CONSTRAINT "book_submissions_book_id_fk" FOREIGN KEY ("book_id") REFERENCES "books"("id") ON DELETE SET NULL;
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS "book_submissions_book_id_idx" ON "book_submissions"("book_id");
-- backfill book_submissions.book_id from books.source_submission_id
UPDATE "book_submissions" bs SET "book_id" = b."id"
FROM "books" b WHERE b."source_submission_id" = bs."id" AND bs."book_id" IS NULL;

-- 5. signup_books.book_id (additive — keep book_name during transition)
ALTER TABLE "signup_books" ADD COLUMN IF NOT EXISTS "book_id" text;
UPDATE "signup_books" sb SET "book_id" = lbm."book_id"
FROM "legacy_book_mappings" lbm
WHERE lbm."legacy_source" = 'book_name' AND lbm."legacy_id" = sb."book_name" AND sb."book_id" IS NULL;
CREATE INDEX IF NOT EXISTS "signup_books_book_id_idx" ON "signup_books"("book_id");
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'signup_books_book_id_fk') THEN
    ALTER TABLE "signup_books" ADD CONSTRAINT "signup_books_book_id_fk" FOREIGN KEY ("book_id") REFERENCES "books"("id") ON DELETE CASCADE;
  END IF;
END $$;

-- 6. book_priorities.book_id (additive — keep book_name during transition)
ALTER TABLE "book_priorities" ADD COLUMN IF NOT EXISTS "book_id" text;
UPDATE "book_priorities" bp SET "book_id" = lbm."book_id"
FROM "legacy_book_mappings" lbm
WHERE lbm."legacy_source" = 'book_name' AND lbm."legacy_id" = bp."book_name" AND bp."book_id" IS NULL;
CREATE INDEX IF NOT EXISTS "book_priorities_book_id_idx" ON "book_priorities"("book_id");
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'book_priorities_book_id_fk') THEN
    ALTER TABLE "book_priorities" ADD CONSTRAINT "book_priorities_book_id_fk" FOREIGN KEY ("book_id") REFERENCES "books"("id") ON DELETE CASCADE;
  END IF;
END $$;

